{'script': 'from manim import *\n\nclass ExplanationScene(Scene):\n    def construct(self):\n        # Enhanced title with personalization\n        title = Text("Division basics", font_size=48, color=WHITE, weight=BOLD)\n        subtitle = Text("Personalized Learning", font_size=24, color=LIGHT_BLUE)\n        subtitle.next_to(title, DOWN, buff=0.5)\n        \n        # Grade-appropriate introduction\n        self.play(Create(title), run_time=2)\n        self.play(Create(subtitle), run_time=1.5)\n        self.wait(2)\n        \n        # Clear and transition\n        self.play(FadeOut(title), FadeOut(subtitle))\n        \n        # Main learning content adapted to style\n        if "mixed" == "visual":\n            content = Text("Let\'s visualize Division basics!", font_size=40, color=WHITE)\n            diagram = Circle(radius=2, color=LIGHT_BLUE)\n            diagram.next_to(content, DOWN, buff=1)\n            \n            self.play(Create(content))\n            self.play(Create(diagram))\n            self.wait(3)\n            \n        elif "mixed" == "kinesthetic":\n            content = Text("Let\'s explore Division basics step by step!", font_size=40, color=WHITE)\n            steps = VGroup()\n            for i in range(3):\n                step = Text(f"Step {i+1}: Learn about Division basics", font_size=32, color=LIGHT_BLUE)\n                step.move_to(UP * (1-i) * 0.8)\n                steps.add(step)\n            \n            self.play(Create(content))\n            self.wait(1)\n            self.play(FadeOut(content))\n            \n            for step in steps:\n                self.play(Create(step), run_time=1.5)\n                self.wait(1)\n        \n        else:  # auditory or mixed\n            content = Text("Understanding Division basics is important\\nfor Grade 4 students", \n                         font_size=36, color=WHITE)\n            explanation = Text("This concept builds on what you already know\\nand prepares you for future learning", \n                             font_size=32, color=LIGHT_BLUE)\n            explanation.next_to(content, DOWN, buff=1)\n            \n            self.play(Create(content))\n            self.wait(2)\n            self.play(Create(explanation))\n            self.wait(3)\n        \n        # Personalized encouragement\n        encouragement = Text("Great job learning about Division basics!\\nYou\'re making excellent progress!", \n                           font_size=40, color=GREEN)\n        \n        self.play(FadeOut(*self.mobjects))\n        self.play(Create(encouragement))\n        self.wait(3)\n        \n        # Final fade\n        self.play(FadeOut(encouragement))', 'metadata': {'complexity': 'simple', 'learning_style_adapted': 'mixed', 'grade_appropriate': True, 'personalization_level': 'high', 'concepts_covered': ['Division basics'], 'interactive_elements': []}}